const body = $input.first().json.body;
const jobText = body.job_text || '';
const company = body.company || 'Unknown';
if (!jobText) return [{ json: { error: 'No job_text provided' } }];
const safeJob = jobText.substring(0, 6000);
return [{ json: { company, job_text: safeJob, received_at: new Date().toISOString(), char_count: safeJob.length } }];

const response = $input.first().json;
let text = '';
try {
  const parts = response.candidates[0].content.parts;
  for (const p of parts) { if (!p.thought && p.text) text = p.text; }
  if (!text) text = parts[parts.length - 1].text || '';
} catch (e) {
  return [{ json: { error: 'No Gemini response', stage: 'parse' } }];
}
text = text.replace(/```json/gi, '').replace(/```/g, '').trim();
try {
  const parsed = JSON.parse(text);
  parsed._raw_tokens = text.length;
  return [{ json: parsed }];
} catch (e) {
  return [{ json: { error: e.message, stage: 'json_parse', first_200: text.substring(0, 200) } }];
}

const d = $input.first().json;
if (d.error) return [{ json: d }];

const totalKw = (d.ats_keywords || []).length;
const inCv = (d.ats_keywords_in_cv || []).length;
const missing = (d.ats_keywords_missing || []).length;
const coverage = totalKw > 0 ? Math.round((inCv / totalKw) * 100) : 0;

const fitLabel = d.fit_score >= 4 ? 'STRONG' : d.fit_score >= 3 ? 'MODERATE' : 'WEAK';
const atsLabel = parseInt(d.ats_score) >= 80 ? 'HIGH' : parseInt(d.ats_score) >= 60 ? 'MEDIUM' : 'LOW';

return [{ json: {
  ...d,
  analysis: {
    keyword_coverage: coverage,
    keyword_total: totalKw,
    keyword_matched: inCv,
    keyword_missing: missing,
    fit_label: fitLabel,
    ats_label: atsLabel,
    recommendation: d.fit_score >= 3 ? 'APPLY' : 'SKIP',
    analysed_at: new Date().toISOString()
  }
} }];

const d = $input.first().json;
if (d.error) return [{ json: d }];

return [{ json: {
  pipeline_version: '2.0',
  processed_at: new Date().toISOString(),
  title: d.title,
  company: d.company,
  location: d.location,
  scores: {
    fit: d.fit_score,
    ats: d.ats_score,
    fit_label: d.analysis.fit_label,
    ats_label: d.analysis.ats_label,
    recommendation: d.analysis.recommendation
  },
  keywords: {
    total: d.analysis.keyword_total,
    matched: d.analysis.keyword_matched,
    missing: d.analysis.keyword_missing,
    coverage_pct: d.analysis.keyword_coverage,
    missing_list: d.ats_keywords_missing || [],
    optimised_skills_line: d.ats_optimised_skills_line || ''
  },
  tailored: {
    profile: d.tailored_profile || '',
    bullets: d.tailored_bullets || [],
    cover_letter: d.cover_letter || ''
  },
  gaps: d.gaps || [],
  matching_skills: d.matching_skills || [],
  key_requirements: d.key_requirements || [],
  ats_tips: d.ats_tips || []
} }];
